sql:
SELECT REPLACE(county_name, ' County', '') AS county_name
FROM counties
ORDER BY county_name;

external_knowledge:
- 'Wealthiest counties' refers to the counties with the highest median income;
- 'Top three' means the counties ranked 1st, 2nd, and 3rd in each state;
- 'Median income' is a statistical measure of the income distribution.

sql:
SELECT MAX(population) AS highest_population_estimate
FROM population_estimates
WHERE year = 2020 AND estimate_source = 'Survey';

SELECT county_id, stat_value AS unemployment_rate, stat_source
FROM county_statistics
WHERE stat_year = 2020 AND stat_type = 'Unemployment Rate';

